import java.util.*;

public class Solution {
    public static long[] solve(String[] words) {
        int n = words.length;
        long[] answer = new long[n];

        for (int i = 0; i < n; i++) {
            List<String> newWords = new ArrayList<>();
            for (int j = 0; j < n; j++) {
                if (j != i) {
                    newWords.add(words[j]);
                }
            }

            long maxLcp = 0;
            for (int j = 0; j < newWords.size() - 1; j++) {
                int lcp = lcp(newWords.get(j), newWords.get(j + 1));
                maxLcp = Math.max(maxLcp, lcp);
            }
            answer[i] = maxLcp;
        }

        return answer;
    }

    private static int lcp(String s1, String s2) {
        int minLen = Math.min(s1.length(), s2.length());
        int i = 0;
        while (i < minLen && s1.charAt(i) == s2.charAt(i)) {
            i++;
        }
        return i;
    }
}
